INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-d0d1b9a2-moex-00074', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司 X1 年 12 月 31 日銀行對帳單之銀行帳戶餘額為$27,200，會計紀錄之銀行帳戶餘額為 $35,200。其他資訊如下：', '["X1年11月30日與12月31日之在途存款分別為$6,000與$8,000", "X1年11月30日與12月31日之未兌現支票分別為$4,000與$2,000", "銀行通知甲公司X1年12月之利息收入之金額為$80", "甲公司簽發支票給供應商金額為$3,600，會計紀錄誤記為$6,300 ⑤甲公司收自客戶之即期支票，因客戶存款不足跳票金額為$4,800 甲公司係每月底編製銀行調節表，甲公司X1年12月31日正確之銀行帳戶餘額為何？"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00075', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司之期末盤點存貨之相關資料如下： 存貨 類別 數量 單位成本 估計淨變現價值 A 甲 100 $10 $5 B 甲 200 20 22 C 乙 100 10 15 D 乙 200 20 18 E 乙 300 30 31 若甲公司存貨按成本與淨變現價值孰低衡量，則其存貨以逐項比較法及分類比較法（上表中之兩 類別）兩方法下餘額差異數為若干？', '["$600", "$700", "$800", "$900"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00076', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', 'X1 年 1 月 1 日，甲公司以$88,186 購入乙公司發行之債券，另支付手續費$1,000；該債券面額 $100,000、票面利率9%、每年底付息一次；購入日該債券之有效利率為12%。另甲公司於X1年 1月1日將該購入之乙公司債券分類為透過其他綜合損益按公允價值衡量之金融資產。X1年底， 該債券公允價值為$105,000；而X2年6月30日，甲公司以$91,000加計應計利息處分該債券。 甲公司X1與X2年度，因該債券之交易總計應認列之利益為何？', '["$12,214", "$12,814", "$15,114", "$15,314"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00077', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司X1年1月1日以$100,000買入機器設備，該機器設備之折舊會計處理係採用直線法，該 機器設備之估計耐用年限10年，無殘值。前述機器適用重估價模式，且X1年底及X2年之公允 價值分別為$81,000及$90,000。試問X2年度甲公司因該機器認列之其他綜合損益為何？', '["$0", "$9,000其他綜合損失", "$9,000其他綜合利益", "$10,000其他綜合利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00078', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', 'X1年1月1日，甲公司以$200,000,000購入一棟大樓，另支付代書及過戶登記費共計$2,000,000， 帳列係採公允價值模式之投資性不動產，估計該辦公大樓可使用50年，無殘值。X1年底該大樓 公允價值為$220,000,000，則該辦公大樓之相關交易或事項對甲公司X1年度之淨利影響為何？', '["$14,000,000", "$16,000,000", "$18,000,000", "$20,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00079', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X1年1月1日發行10年期之公司債，面額為$1,000,000，票面利率為4%，每年於年底 支付現金利息；債券發行日與甲公司條件類似債券之市場利率為6%。X9年12月31日甲公司支 付現金利息後，於債券市場上買回全數該債券，買回當時條件類似債券之市場利率為3%。甲公司 應認列之公司債提前清償損益為何？', '["損失$9,709", "損失18,868", "損失$28,577", "無需認列任何損益"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00080', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '以下項目為有關權益之會計處理，有幾項為錯誤敘述？', '["股票分割將使財務報表之股本增加", "購入其他公司之股票應認列為庫藏股", "宣告發放股票股利，將使財務報表之權益增加", "減資用以彌補虧損，不會改變財務報表之權益金額。 ⑤在賣出庫藏股時，若股票價格高於購入庫藏股之股票價格，則將認列為利益。 ⑥以現金購回公司已經發行且流通在外股票之交易，可能使財務報表之權益增加或減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00081', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司發行普通股與特別股，普通股與特別股之額定股數分別為280,000股與10,000股，普通股 與特別股之每股面額分別為$10與$100；特別股為累積特別股，且特別股之股利率為6%。於X2 年12月31日，已發行且流通在外之普通股為238,000股；已發行且流通在外之特別股為10,000 股，另積欠股利為2年。X2年度，甲公司之淨利為$280,000；假設宣告現金股利為以下兩種情況， 情況一：宣告現金股利$80,000，情況二：宣告現金股利$210,000。以下何者為正確？', '["情況一下普通股與特別股之現金股利分別為$0與$80,000", "情況一下普通股與特別股之現金股利分別為$20,000與$60,000", "情況二下普通股與特別股之現金股利分別為$90,000與$120,000", "情況二下普通股與特別股之現金股利分別為$150,000與$60,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00082', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司之應收帳款係採用預期信用損失之估計方法，X1 年 12 月 31 日之應收帳款總額與備抵損 失分別為$300,000 與$21,000，X2 年 12 月 31 日之應收帳款總額與備抵損失分別為$500,000 與 $45,000。另外，甲公司 X2 年度之銷貨收入為$2,000,000 且均為賒銷，另預期信用減損損失為 $30,000。甲公司以直接法編製X2年度現金流量表時，自客戶之現金收取金額為何？', '["$1,770,000", "$1,794,000", "$1,800,000", "$2,146,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00083', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-113-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司X2年度之銷貨淨額為$4,800,000，且毛利率為40%；計算年度相關財務比率係以360天為 基準。甲公司X1年與X2年資產負債表中之部分項目金額如下： 財務報表金額 X1年12月31日 X2年12月31日 應收帳款 $350,000 $450,000 存貨 150,000 90,000 應付帳款 88,000 100,000 請問甲公司X2年度之淨營業週期為何？', '["30天", "33天", "45天", "57天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "012b0be86317", "answer_pdf_sha1": "849168fab101", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "418", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
